class Solution {
public:
    int findKthNumber(int n, int k) {
        long long cur = 1;
        k--;
        while (k > 0) {
            long long step = 0;
            for (long long i = cur; i <= n; i *= 10) {
                step += min(k / (i - cur), n - i + 1);
                if (step == k) {
                    return i;
                }
                cur = i;
            }
        }
        return 0;
    }
};
```

